import { readFileSync } from 'node:fs';
import path from 'node:path';

const SUPA_REF = 'kvclcdjmjghndxsngfzb';
const POOLER_HOST = `aws-0-us-east-1.pooler.supabase.com`;
const POOLER_PORT = '6543';
const SERVICE_ROLE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzE5NDAyNywiZXhwIjoyMDg4NzcwMDI3fQ.TaTRyViK-8sv3R_g1Me08sEjnyMskGXKF0u-I-PTaQ8';

// Supavisor session pooler uses JWT as password, user = postgres
const connStr = `postgres://postgres:${encodeURIComponent(SERVICE_ROLE_KEY)}@${POOLER_HOST}:${POOLER_PORT}/postgres?sslmode=require`;

console.log('Connecting to Supavisor pooler...');
console.log(`Host: ${POOLER_HOST}:${POOLER_PORT}`);

async function main() {
  const pg = await import('pg');
  const { Pool } = pg.default || pg;
  const pool = new Pool({
    connectionString: connStr,
    ssl: { rejectUnauthorized: false },
    max: 1,
    connectionTimeoutMillis: 15000,
  });

  const client = await pool.connect();
  console.log('✓ Connected to Supabase database');

  // Read the migration SQL
  const sqlPath = path.resolve(process.cwd(), 'expo', 'supabase', 'ivx-zero-data-loss-migration.sql');
  const sql = readFileSync(sqlPath, 'utf8');
  console.log(`Migration SQL loaded (${sql.length} chars)`);

  await client.query(sql);
  console.log('✓ Migration SQL executed successfully');

  // Verify tables created
  const vaultCheck = await client.query("SELECT to_regclass('public.data_vault') as exists");
  console.log(`data_vault table: ${vaultCheck.rows[0]?.exists ? '✓ EXISTS' : '✗ MISSING'}`);

  const snapshotCheck = await client.query("SELECT to_regclass('public.snapshot_metadata') as exists");
  console.log(`snapshot_metadata table: ${snapshotCheck.rows[0]?.exists ? '✓ EXISTS' : '✗ MISSING'}`);

  // Check soft-delete columns on members
  const colCheck = await client.query(`
    SELECT column_name FROM information_schema.columns
    WHERE table_schema='public' AND table_name='members'
    AND column_name IN ('deleted_at','deleted_by','delete_reason')
  `);
  console.log(`Soft-delete columns on members: ${colCheck.rows.length}/3 found`);
  for (const r of colCheck.rows) {
    console.log(`  ✓ ${r.column_name}`);
  }

  // List all tables now
  const tables = await client.query(`
    SELECT table_name FROM information_schema.tables
    WHERE table_schema='public' AND table_type='BASE TABLE'
    ORDER BY table_name
  `);
  console.log(`\nAll public tables (${tables.rows.length}):`);
  for (const r of tables.rows) {
    console.log(`  ${r.table_name}`);
  }

  client.release();
  await pool.end();
  console.log('\n✓ Done');
}

main().catch((err) => {
  console.error('FATAL:', err instanceof Error ? err.message : err);
  process.exit(1);
});
