    WHERE table_schema='public' AND column_name IN ('deleted_at','deleted_by','delete_reason')
    ORDER BY table_name, column_name;
  `);
  console.log(`\nSoft-delete columns (${colRes.length || 'N/A'}):`);
  if (Array.isArray(colRes)) {
    let lastTable = '';
    for (const r of colRes) {
      if (r.table_name !== lastTable) { console.log(`  ${r.table_name}:`); lastTable = r.table_name; }
      console.log(`    ✓ ${r.column_name}`);
    }
  }

  // Row counts
  console.log('\n=== LIVE ROW COUNTS ===');
  const tables = ['members','investors','buyers','waitlist','wallets','ledger','transactions','messages','analytics_events','landing_analytics','data_vault','snapshot_metadata'];
  for (const t of tables) {
    try {
      const res = await execSql(`SELECT count(*) as cnt FROM public."${t}";`);
      const cnt = Array.isArray(res) ? res[0]?.cnt : res?.cnt;
      console.log(`  ${t}: ${cnt}`);
    } catch (e) {
      console.log(`  ${t}: N/A (${e instanceof Error ? e.message.slice(0,60) : 'error'})`);
    }
  }

  // List all tables
  const allTables = await execSql(`
    SELECT table_name FROM information_schema.tables
    WHERE table_schema='public' AND table_type='BASE TABLE'
    ORDER BY table_name;
  `);
  if (Array.isArray(allTables)) {
    console.log(`\nAll public tables (${allTables.length}):`);
    for (const r of allTables) console.log(`  ${r.table_name}`);
  }

  console.log('\n✓ Migration complete');
}

main().catch((err) => {
  console.error('FATAL:', err instanceof Error ? err.message : err);
  process.exit(1);
});
