const SERVICE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzE5NDAyNywiZXhwIjoyMDg4NzcwMDI3fQ.TaTRyViK-8sv3R_g1Me08sEjnyMskGXKF0u-I-PTaQ8';

async function execSql(sql: string): Promise<any> {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/rpc/ivx_exec_sql`, {
    method: 'POST',
    headers: {
      apikey: SERVICE_KEY,
      Authorization: `Bearer ${SERVICE_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ sql_text: sql }),
  });
  const text = await res.text();
  if (!res.ok) throw new Error(`HTTP ${res.status}: ${text.slice(0,300)}`);
  return JSON.parse(text);
}

async function run(label: string, sql: string): Promise<boolean> {
  try {
    const res = await execSql(sql);
    if (res && res.ok === false) {
      console.log(`  ✗ ${label}: ${res.error?.slice(0,100) || 'failed'}`);
      return false;
    }
    console.log(`  ✓ ${label}`);
    return true;
  } catch (e) {
    const msg = e instanceof Error ? e.message.slice(0,100) : String(e);
    // Ignore "already exists" errors
    if (msg.includes('already exists')) {
      console.log(`  ⊙ ${label} (already exists)`);
      return true;
    }
    console.log(`  ✗ ${label}: ${msg}`);
    return false;
  }
}

async function main() {
  // 1. Create data_vault table
  console.log('=== 1. DATA VAULT TABLE ===');
  await run('CREATE data_vault', `
    CREATE TABLE IF NOT EXISTS public.data_vault (
      id          BIGSERIAL PRIMARY KEY,
      vault_id    TEXT        NOT NULL UNIQUE,
      table_name  TEXT        NOT NULL,
      record_id   TEXT,
      action      TEXT        NOT NULL CHECK (action IN ('INSERT','UPDATE','DELETE','TRUNCATE')),
      old_data    JSONB,
      new_data    JSONB,
      user_id     TEXT,
      reason      TEXT,
      hash        TEXT,
      created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
    );
  `);
  await run('idx data_vault table_name', `CREATE INDEX IF NOT EXISTS idx_data_vault_table_name ON public.data_vault (table_name);`);
  await run('idx data_vault record_id', `CREATE INDEX IF NOT EXISTS idx_data_vault_record_id ON public.data_vault (record_id);`);
  await run('idx data_vault created_at', `CREATE INDEX IF NOT EXISTS idx_data_vault_created_at ON public.data_vault (created_at DESC);`);
  await run('idx data_vault vault_id', `CREATE INDEX IF NOT EXISTS idx_data_vault_vault_id ON public.data_vault (vault_id);`);
  await run('RLS data_vault', `ALTER TABLE public.data_vault ENABLE ROW LEVEL SECURITY;`);

  // 2. Create snapshot_metadata table
  console.log('\n=== 2. SNAPSHOT METADATA TABLE ===');
  await run('CREATE snapshot_metadata', `
    CREATE TABLE IF NOT EXISTS public.snapshot_metadata (
      id            BIGSERIAL PRIMARY KEY,
      snapshot_id   TEXT        NOT NULL UNIQUE,
      tables        JSONB       NOT NULL,
      total_rows    BIGINT      NOT NULL DEFAULT 0,
      total_bytes   BIGINT      NOT NULL DEFAULT 0,
      status        TEXT        NOT NULL DEFAULT 'completed',
      triggered_by  TEXT,
      created_at    TIMESTAMPTZ NOT NULL DEFAULT now()
    );
  `);
  await run('idx snapshot_metadata', `CREATE INDEX IF NOT EXISTS idx_snapshot_metadata_created_at ON public.snapshot_metadata (created_at DESC);`);
  await run('RLS snapshot_metadata', `ALTER TABLE public.snapshot_metadata ENABLE ROW LEVEL SECURITY;`);

  // 3. Get list of existing tables
  console.log('\n=== 3. FINDING EXISTING TABLES ===');
  // The RPC returns {ok:true} for DDL, but for SELECTs it may return data differently
  // Let's query via REST API instead
  const swaggerRes = await fetch(`${SUPABASE_URL}/rest/v1/`, {
    headers: { apikey: SERVICE_KEY, Authorization: `Bearer ${SERVICE_KEY}` },
  });
  const swagger = await swaggerRes.json() as any;
  const allTableNames = Object.keys(swagger.definitions || {});
  console.log(`Tables visible in PostgREST: ${allTableNames.length}`);

  const protectedTableNames = [
    'members','waitlist','investors','buyers','wallets','transactions',
    'messages','analytics_events','landing_analytics','ledger',
    'wire_transfers','referrals','profiles'
  ];
  const existingProtected = protectedTableNames.filter(t => allTableNames.includes(t));
  console.log(`Protected tables found: ${existingProtected.join(', ')}`);

  // 4. Add soft-delete columns to each table
  console.log('\n=== 4. SOFT-DELETE COLUMNS ===');
  for (const table of existingProtected) {
    // Try adding each column - ignore errors if already exists
