async function execSql(sql: string): Promise<any> {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/rpc/ivx_exec_sql`, {
    method: 'POST',
    headers: { apikey: SERVICE_KEY, Authorization: `Bearer ${SERVICE_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ sql_text: sql }),
  });
  const text = await res.text();
  if (!res.ok) throw new Error(`HTTP ${res.status}: ${text.slice(0,200)}`);
  return JSON.parse(text);
}

async function restGet(table: string, query: string = 'select=*'): Promise<any> {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?${query}`, {
    headers: { apikey: SERVICE_KEY, Authorization: `Bearer ${SERVICE_KEY}` },
  });
  return res.json();
}

async function restPost(table: string, body: any): Promise<any> {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
    method: 'POST',
    headers: { apikey: SERVICE_KEY, Authorization: `Bearer ${SERVICE_KEY}`, 'Content-Type': 'application/json', Prefer: 'return=representation' },
    body: JSON.stringify(body),
  });
  return { status: res.status, data: await res.json() };
}

async function restPatch(table: string, query: string, body: any): Promise<any> {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?${query}`, {
    method: 'PATCH',
    headers: { apikey: SERVICE_KEY, Authorization: `Bearer ${SERVICE_KEY}`, 'Content-Type': 'application/json', Prefer: 'return=representation' },
    body: JSON.stringify(body),
  });
  return { status: res.status, data: await res.json() };
}

async function main() {
  console.log('=== IVX RECOVERY DRILL ===\n');

  const drillSteps: { step: string; passed: boolean; detail: string }[] = [];
  const testEmail = `drill-test-${Date.now()}@ivxholding.com`;

  // Step 1: Create test member
  console.log('Step 1: Create test member...');
  const createRes = await restPost('members', {
    full_name: 'Drill Test Member',
    email: testEmail,
    phone: '+15550000000',
    member_type: 'member',
    source: 'recovery_drill',
    source_detail: 'drill-test',
    verification_status: 'unverified',
    sms_verified: false,
    email_verified: false,
    investor_interest: '',
    preferred_zipcode: '',
    budget_range: '',
  });
  const testMember = Array.isArray(createRes.data) ? createRes.data[0] : null;
  if (testMember) {
    drillSteps.push({ step: 'create_test_member', passed: true, detail: `Created member ${testMember.member_id}` });
    console.log(`  ✓ Created: ${testMember.member_id}`);
  } else {
    drillSteps.push({ step: 'create_test_member', passed: false, detail: 'Failed to create' });
    console.log(`  ✗ Failed: ${JSON.stringify(createRes.data).slice(0,100)}`);
  }

  // Step 2: Soft-delete (archive) the test member
  if (testMember) {
    console.log('\nStep 2: Soft-delete (archive) test member...');
    const delRes = await restPatch('members', `member_id=eq.${testMember.member_id}`, {
      deleted_at: new Date().toISOString(),
      deleted_by: 'recovery_drill',
      delete_reason: 'drill test - soft delete verification',
    });
    const patched = Array.isArray(delRes.data) ? delRes.data[0] : null;
    if (patched && patched.deleted_at) {
      drillSteps.push({ step: 'soft_delete_member', passed: true, detail: `Soft-deleted at ${patched.deleted_at}` });
      console.log(`  ✓ Soft-deleted: deleted_at=${patched.deleted_at}`);
    } else {
      drillSteps.push({ step: 'soft_delete_member', passed: false, detail: 'Soft-delete failed' });
      console.log(`  ✗ Failed: ${JSON.stringify(delRes.data).slice(0,100)}`);
    }

    // Step 3: Verify member is hidden from normal queries (filter deleted_at IS NULL)
    console.log('\nStep 3: Verify soft-deleted member is hidden from normal queries...');
    const activeMembers = await restGet('members', 'select=member_id&deleted_at=is.null');
    const isActive = Array.isArray(activeMembers) && activeMembers.some((m: any) => m.member_id === testMember.member_id);
    if (!isActive) {
      drillSteps.push({ step: 'hidden_from_normal_ui', passed: true, detail: 'Soft-deleted member hidden from active query' });
      console.log(`  ✓ Hidden from active query`);
    } else {
      drillSteps.push({ step: 'hidden_from_normal_ui', passed: false, detail: 'Member still visible' });
      console.log(`  ✗ Still visible`);
    }

    // Step 4: Restore the soft-deleted member
    console.log('\nStep 4: Restore soft-deleted member...');
    const restoreRes = await restPatch('members', `member_id=eq.${testMember.member_id}`, {
      deleted_at: null,
      deleted_by: null,
      delete_reason: null,
    });
    const restored = Array.isArray(restoreRes.data) ? restoreRes.data[0] : null;
    if (restored && !restored.deleted_at) {
      drillSteps.push({ step: 'restore_member', passed: true, detail: 'Member restored - deleted_at cleared' });
      console.log(`  ✓ Restored: deleted_at=null`);
    } else {
      drillSteps.push({ step: 'restore_member', passed: false, detail: 'Restore failed' });
      console.log(`  ✗ Failed`);
    }

    // Step 5: Verify member is visible again
    console.log('\nStep 5: Verify restored member is visible in active queries...');
    const activeAfter = await restGet('members', 'select=member_id&deleted_at=is.null');
    const isVisibleAfter = Array.isArray(activeAfter) && activeAfter.some((m: any) => m.member_id === testMember.member_id);
    if (isVisibleAfter) {
      drillSteps.push({ step: 'visible_after_restore', passed: true, detail: 'Member visible in active query after restore' });
      console.log(`  ✓ Visible in active query`);
    } else {
      drillSteps.push({ step: 'visible_after_restore', passed: false, detail: 'Member not visible after restore' });
      console.log(`  ✗ Not visible`);
    }

    // Step 6: Save to data_vault (simulate vault capture)
    console.log('\nStep 6: Write to data_vault...');
    const vaultRes = await restPost('data_vault', {
      vault_id: `vault-${Date.now()}-${testMember.member_id.slice(0,8)}`,
      table_name: 'members',
      record_id: testMember.member_id,
      action: 'UPDATE',
      old_data: { deleted_at: new Date().toISOString(), deleted_by: 'recovery_drill' },
      new_data: { deleted_at: null, deleted_by: null },
      user_id: 'recovery_drill',
      reason: 'drill test - vault capture verification',
      hash: `sha256-${Date.now()}`,
    });
    if (vaultRes.status === 201) {
      drillSteps.push({ step: 'data_vault_capture', passed: true, detail: 'Vault record written successfully' });
      console.log(`  ✓ Vault record written`);
    } else {
      drillSteps.push({ step: 'data_vault_capture', passed: false, detail: `Failed: HTTP ${vaultRes.status}` });
      console.log(`  ✗ Failed: ${vaultRes.status}`);
    }

    // Step 7: Verify vault record can be retrieved
    console.log('\nStep 7: Verify vault record retrieval...');
    const vaultRecords = await restGet('data_vault', `table_name=eq.members&record_id=eq.${testMember.member_id}&select=*`);
    if (Array.isArray(vaultRecords) && vaultRecords.length > 0) {
      drillSteps.push({ step: 'vault_retrieval', passed: true, detail: `Found ${vaultRecords.length} vault record(s)` });
      console.log(`  ✓ Found ${vaultRecords.length} vault record(s)`);
    } else {
      drillSteps.push({ step: 'vault_retrieval', passed: false, detail: 'No vault records found' });
      console.log(`  ✗ No records found`);
    }
  }

  // Step 8: Test wallet entry + attempt delete (should be soft-delete only)
  console.log('\nStep 8: Create test wallet entry...');
  const walletRes = await restPost('wallets', {
    user_id: 'drill-test-user',
    available: 100,
    pending: 0,
    invested: 0,
    total: 100,
    currency: 'USD',
  });
  const testWallet = Array.isArray(walletRes.data) ? walletRes.data[0] : null;
  if (testWallet) {
    drillSteps.push({ step: 'create_wallet', passed: true, detail: `Created wallet ${testWallet.id}` });
    console.log(`  ✓ Created wallet: ${testWallet.id}`);

    // Soft-delete the wallet
    console.log('\nStep 9: Soft-delete wallet (archive, not hard delete)...');
    const walletDel = await restPatch('wallets', `id=eq.${testWallet.id}`, {
      deleted_at: new Date().toISOString(),
      deleted_by: 'recovery_drill',
      delete_reason: 'drill test',
    });
    if (walletDel.status === 200 || walletDel.status === 204) {
      drillSteps.push({ step: 'soft_delete_wallet', passed: true, detail: 'Wallet soft-deleted (not hard deleted)' });
      console.log(`  ✓ Soft-deleted (archived, not hard deleted)`);
    } else {
      drillSteps.push({ step: 'soft_delete_wallet', passed: false, detail: 'Failed' });
      console.log(`  ✗ Failed`);
    }
  }

  // Step 10: Take first snapshot
  console.log('\nStep 10: Take first snapshot of all critical tables...');
  const snapshotTables = ['members','investors','buyers','waitlist','wallets','ledger','transactions','messages','analytics_events','landing_analytics'];
  let totalRows = 0;
  const tableCounts: Record<string, number> = {};

  for (const t of snapshotTables) {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/${t}?select=*`, {
      headers: { apikey: SERVICE_KEY, Authorization: `Bearer ${SERVICE_KEY}`, Prefer: 'count=exact', Range: '0-0' },
    });
    const range = res.headers.get('content-range');
    const count = range ? parseInt(range.split('/').pop() || '0') : 0;
    tableCounts[t] = count;
    totalRows += count;
  }

  const snapshotRes = await restPost('snapshot_metadata', {
    snapshot_id: `snap-${Date.now()}`,
    tables: tableCounts,
    total_rows: totalRows,
    total_bytes: 0,
    status: 'completed',
    triggered_by: 'recovery_drill',
